286→func humanBytes(b int64) string {
287→	if b == 0 {
288→		return "—"
289→	}
290→	const unit = 1024
291→	if b < unit {
292→		return fmt.Sprintf("%d B", b)
293→	}
294→	div, exp := int64(unit), 0
295→	for n := b / unit; n >= unit; n /= unit {
296→		div *= unit
297→		exp++
298→	}
299→	return fmt.Sprintf("%.1f %cB", float64(b)/float64(div), "KMGTPE"[exp])
300→}
